import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import TopBar from '../components/layout/TopBar';
import BottomNav from '../components/layout/BottomNav';
import { Pill, Spinner, EmptyState } from '../components/common';
import { getGyodoks } from '../supabase/db';

const TABS = [
  { key: 'all',       label: '전체' },
  { key: 'active',    label: '진행 중' },
  { key: 'completed', label: '종료' },   // ← '참여 완료' → '종료'
  { key: 'upcoming',  label: '예정' },
];

const STATUS_PILL = {
  active:    { label: '진행 중', variant: 'green' },
  completed: { label: '종료',   variant: 'gray' },   // ← '완료' → '종료'
  upcoming:  { label: '예정',   variant: 'amber' },
};

export default function GyodokListPage() {
  const { user }  = useAuth();
  const navigate  = useNavigate();
  const [tab,     setTab]     = useState('all');
  const [list,    setList]    = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user) return;
    getGyodoks(user.id)
      .then(data => setList(data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [user]);

const STATUS_ORDER = { active: 0, upcoming: 1, completed: 2 };

const filtered = (tab === 'all' ? list : list.filter(g => g.status === tab))
  .sort((a, b) => {
    // 1차: 상태 순서 (진행중 → 예정 → 종료)
    const statusDiff = (STATUS_ORDER[a.status] ?? 3) - (STATUS_ORDER[b.status] ?? 3);
    if (statusDiff !== 0) return statusDiff;
    // 2차: 시작일 역순 (최신이 위)
    const da = a.startDate ? new Date(a.startDate) : new Date(0);
    const db = b.startDate ? new Date(b.startDate) : new Date(0);
    return db - da;
  });

  return (
    <div className="page">
      <TopBar
  title="교독"
  right={
    user?.isAdmin && (
      <button
        onClick={() => navigate('/admin/create')}
        style={{
          padding: '5px 12px',
          borderRadius: 'var(--radius-full)',
          background: 'var(--accent-primary)',
          border: 'none',
          fontSize: 12, color: '#fff', fontWeight: 500,
          cursor: 'pointer', fontFamily: 'var(--font-sans)',
        }}
      >
        + 교독 생성
      </button>
    )
  }
/>

      {/* 탭 필터 */}
      <div style={{
        display: 'flex', gap: 6,
        overflowX: 'auto', padding: '10px 14px',
        scrollbarWidth: 'none',
      }}>
        {TABS.map(t => (
          <button
            key={t.key}
            onClick={() => setTab(t.key)}
            style={{
              flexShrink: 0,
              padding: '5px 14px',
              borderRadius: 'var(--radius-full)',
              fontSize: 12, fontWeight: 500,
              border: `0.5px solid ${tab === t.key ? 'var(--accent-green)' : 'var(--border-input)'}`,
              background: tab === t.key ? 'var(--accent-green)' : 'var(--bg-page)',
              color: tab === t.key ? 'var(--accent-green-dark)' : 'var(--text-tertiary)',
              cursor: 'pointer',
              transition: 'all var(--transition-fast)',
              fontFamily: 'var(--font-sans)',
            }}
          >
            {t.label}
          </button>
        ))}
      </div>

      <div style={{ padding: '0 14px' }}>
        {loading && <Spinner />}

        {!loading && filtered.length === 0 && (
          <EmptyState
            message="교독 모임이 없습니다"
            sub={tab === 'all' ? '관리자가 모임을 생성하면 여기에 표시됩니다' : ''}
          />
        )}

        {filtered.map(g => (
          <GyodokCard
            key={g.id}
            gyodok={g}
            onClick={() => navigate(`/gyodok/${g.id}`)}
          />
        ))}
      </div>

      <BottomNav />
    </div>
  );
}

/* ── 교독 목록 카드 ── */
function GyodokCard({ gyodok, onClick }) {
  const pill = STATUS_PILL[gyodok.status] || STATUS_PILL.upcoming;
  const isCompleted = gyodok.status === 'completed';

  // 책 커버 3장 콜라주 색상
  const collageColors = ['var(--accent-green)', 'var(--accent-amber)', 'var(--color-beige)'];

  return (
    <div
      onClick={onClick}
      style={{
        background: 'var(--bg-card)',
        borderRadius: 'var(--radius-lg)',
        border: '0.5px solid var(--border-default)',
        padding: 12,
        marginBottom: 8,
        display: 'flex',
        gap: 10,
        alignItems: 'flex-start',
        cursor: 'pointer',
        opacity: isCompleted ? 0.7 : 1,
        transition: 'opacity var(--transition-fast)',
        boxShadow: 'var(--shadow-card)',
      }}
    >
      {/* 책 콜라주 */}
      <div style={{
        width: 60, height: 78,
        flexShrink: 0,
        borderRadius: 8,
        overflow: 'hidden',
        display: 'flex',
      }}>
        {(gyodok.bookCovers || [null, null, null]).slice(0, 3).map((url, i) => (
          <div
            key={i}
            style={{
              flex: 1,
              background: url ? 'transparent' : collageColors[i],
              marginLeft: i > 0 ? -5 : 0,
              borderRadius: i === 0 ? '6px 0 0 6px' : i === 2 ? '0 6px 6px 0' : 0,
              overflow: 'hidden',
            }}
          >
            {url && <img src={url} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
          </div>
        ))}
      </div>

      {/* 정보 */}
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginBottom: 4 }}>
          <Pill variant={pill.variant}>{pill.label}</Pill>
          {gyodok.round && (
            <span style={{ fontSize: 10, color: 'var(--text-tertiary)' }}>{gyodok.round}회차</span>
          )}
        </div>
        <div style={{
          fontSize: 13, fontWeight: 500, color: 'var(--text-primary)',
          marginBottom: 3,
          overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
        }}>
          {gyodok.title}
        </div>
        <div style={{ fontSize: 10, color: 'var(--text-tertiary)', lineHeight: 1.7 }}>
          {gyodok.startDate && formatDate(gyodok.startDate)}
          {gyodok.endDate ? ` ~ ${formatDate(gyodok.endDate)}` : ''}
        </div>

        {/* 참여자 아바타 */}
        {gyodok.participantIds?.length > 0 && (
          <div style={{ display: 'flex', marginTop: 6 }}>
            {gyodok.participantIds.slice(0, 3).map((pid, i) => (
              <div key={pid} style={{
                width: 18, height: 18, borderRadius: '50%',
                background: ['var(--accent-green)', 'var(--accent-amber)', 'var(--accent-primary)'][i % 3],
                border: '1.5px solid var(--bg-page)',
                marginLeft: i > 0 ? -5 : 0,
              }} />
            ))}
            {gyodok.participantIds.length > 3 && (
              <div style={{
                width: 18, height: 18, borderRadius: '50%',
                background: 'var(--border-strong)',
                border: '1.5px solid var(--bg-page)',
                marginLeft: -5,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 8, color: 'var(--text-secondary)',
              }}>
                +{gyodok.participantIds.length - 3}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

function formatDate(ts) {
  if (!ts) return '';
  try {
    const d = ts.toDate ? ts.toDate() : new Date(ts);
    return `${d.getFullYear()}.${String(d.getMonth() + 1).padStart(2, '0')}.${String(d.getDate()).padStart(2, '0')}`;
  } catch { return ''; }
}
